        suffix_odd[k] = suffix_odd[k + 1];
        suffix_even[k] = suffix_even[k + 1];

        // Update based on nums[k] parity
        // Note: For positive numbers, x % 2 == 1 means odd, x % 2 == 0 means even.
        if (nums[k] % 2 != 0) { // Odd
            suffix_odd[k]++;
        } else { // Even
            suffix_even[k]++;
        }
